const body = $input.first().json.body || {};
const periode = body.periode || "aujourd'hui";
const calendarId = body.calendar_id || (typeof process !== 'undefined' && process.env?.CLIENT_CALENDAR_ID) || 'primary';

function startOfDay(d) { const s = new Date(d); s.setHours(0,0,0,0); return s; }
function endOfDay(d)   { const e = new Date(d); e.setHours(23,59,59,999); return e; }

const now = new Date();
let timeMin, timeMax;

if (periode === 'demain' || periode === 'tomorrow') {
  const d = new Date(now); d.setDate(d.getDate() + 1);
  timeMin = startOfDay(d); timeMax = endOfDay(d);
} else if (periode === 'semaine' || periode === 'week') {
  const day = now.getDay();
  const monday = new Date(now); monday.setDate(now.getDate() - (day === 0 ? 6 : day - 1));
  const sunday = new Date(monday); sunday.setDate(monday.getDate() + 6);
  timeMin = startOfDay(monday); timeMax = endOfDay(sunday);
} else {
  timeMin = startOfDay(now); timeMax = endOfDay(now);
}

return [{ json: { periode, calendarId, timeMin: timeMin.toISOString(), timeMax: timeMax.toISOString() } }];

const items = $input.all();
const events = items.map(i => i.json).filter(e => e.id);
const periode = $('Calcul plage horaire').first().json.periode;
return [{ json: { ok: true, periode, events, count: events.length, fetched_at: new Date().toISOString() } }];
